import { useState } from 'react'
import { Card, CardContent, CardHeader, CardTitle, CardDescription, CardFooter } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Progress } from '@/components/ui/progress'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Separator } from '@/components/ui/separator'
import { toast } from 'sonner'

const STEPS = [
  { id: 'step-1', title: '<!-- Step 1 title -->' },
  { id: 'step-2', title: '<!-- Step 2 title -->' },
  { id: 'review', title: 'Review & confirm' },
]

export default function App() {
  const [step, setStep] = useState(0)

  const isFirst = step === 0
  const isLast = step === STEPS.length - 1
  const progress = ((step + 1) / STEPS.length) * 100

  return (
    <div className="min-h-screen flex flex-col">

      {/* Progress header */}
      <header className="px-6 py-4 border-b flex flex-col gap-3">
        <div className="flex items-center justify-between">
          <span className="text-sm text-muted-foreground">
            Step {step + 1} of {STEPS.length}
          </span>
          <span className="text-sm font-medium">{STEPS[step].title}</span>
        </div>
        <Progress value={progress} className="h-1.5" />
      </header>

      {/* Step content */}
      <main className="flex-1 flex items-start justify-center py-12 px-6">
        <Card className="w-full max-w-lg">
          <CardHeader>
            <CardTitle>{STEPS[step].title}</CardTitle>
            <CardDescription><!-- Step guidance text --></CardDescription>
          </CardHeader>
          <CardContent className="flex flex-col gap-4">
            {/* Step-specific fields rendered conditionally on step index */}
            {step === 0 && (
              <>
                {/* Step 1 fields */}
              </>
            )}
            {step === 1 && (
              <>
                {/* Step 2 fields */}
              </>
            )}
            {isLast && (
              <>
                {/* Review summary — list of collected values */}
              </>
            )}
          </CardContent>
          <CardFooter className="flex justify-between">
            <Button
              variant="outline"
              onClick={() => setStep(s => s - 1)}
              disabled={isFirst}
            >
              Back
            </Button>
            <Button
              onClick={() => {
                if (isLast) {
                  toast.success('Submitted!')
                } else {
                  setStep(s => s + 1)
                }
              }}
            >
              {isLast ? '<!-- Submit label -->' : 'Continue'}
            </Button>
          </CardFooter>
        </Card>
      </main>

    </div>
  )
}

import { useState, useRef, useEffect } from 'react'
import { ScrollArea } from '@/components/ui/scroll-area'
import { Textarea } from '@/components/ui/textarea'
import { Button } from '@/components/ui/button'
import { Avatar, AvatarFallback } from '@/components/ui/avatar'
import { Separator } from '@/components/ui/separator'
import { Badge } from '@/components/ui/badge'
import { cn } from '@/lib/utils'

export default function App() {
  const [messages, setMessages] = useState([])
  const [input, setInput] = useState('')
  const bottomRef = useRef(null)

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [messages])

  const send = () => {
    if (!input.trim()) return
    setMessages(m => [...m, { role: 'user', content: input }])
    setInput('')
  }

  return (
    <div className="min-h-screen flex">

      {/* Session list sidebar */}
      <aside className="w-64 border-r flex flex-col shrink-0">
        <div className="px-4 py-3 border-b">
          <Button className="w-full" variant="outline" size="sm">New conversation</Button>
        </div>
        <ScrollArea className="flex-1">
          <div className="flex flex-col gap-1 p-2">
            {/* Session items */}
          </div>
        </ScrollArea>
      </aside>

      {/* Conversation area */}
      <div className="flex-1 flex flex-col">

        {/* Thread header */}
        <header className="border-b px-6 py-3 flex items-center gap-3 shrink-0">
          <Avatar className="h-7 w-7"><AvatarFallback>A</AvatarFallback></Avatar>
          <span className="font-medium text-sm"><!-- Conversation title or participant name --></span>
        </header>

        {/* Message list */}
        <ScrollArea className="flex-1 px-6 py-4">
          <div className="flex flex-col gap-4 max-w-2xl mx-auto">
            {messages.map((m, i) => (
              <div key={i} className={cn('flex gap-3', m.role === 'user' && 'flex-row-reverse')}>
                <Avatar className="h-7 w-7 shrink-0">
                  <AvatarFallback>{m.role === 'user' ? 'U' : 'A'}</AvatarFallback>
                </Avatar>
                <div className={cn(
                  'rounded-lg px-4 py-2.5 text-sm max-w-prose',
                  m.role === 'user' ? 'bg-primary text-primary-foreground' : 'bg-muted'
                )}>
                  {m.content}
                </div>
              </div>
            ))}
            <div ref={bottomRef} />
          </div>
        </ScrollArea>

        {/* Composer */}
        <div className="border-t px-6 py-4 shrink-0">
          <div className="max-w-2xl mx-auto flex gap-3 items-end">
            <Textarea
              value={input}
              onChange={e => setInput(e.target.value)}
              onKeyDown={e => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); send() } }}
              placeholder="Type a message..."
              rows={2}
              className="resize-none flex-1"
            />
            <Button onClick={send} className="shrink-0">Send</Button>
          </div>
        </div>

      </div>
    </div>
  )
}

import { useState } from 'react'
import { ScrollArea } from '@/components/ui/scroll-area'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { Tabs, TabsList, TabsTrigger } from '@/components/ui/tabs'
import { Separator } from '@/components/ui/separator'
import { Avatar, AvatarFallback } from '@/components/ui/avatar'
import { Card, CardContent } from '@/components/ui/card'
import { cn } from '@/lib/utils'

export default function App() {
  const [filter, setFilter] = useState('inbox')
  const [selected, setSelected] = useState(null)

  return (
    <div className="min-h-screen flex">

      {/* Section nav */}
      <aside className="w-44 border-r flex flex-col shrink-0">
        <div className="px-4 py-3 border-b">
          <span className="font-bold font-heading text-sm">Inbox</span>
        </div>
        <nav className="flex flex-col gap-1 p-2">
          {[['inbox','Inbox',4],['done','Done',0],['snoozed','Snoozed',1]].map(([id, label, count]) => (
            <button
              key={id}
              onClick={() => setFilter(id)}
              className={cn('flex items-center justify-between text-sm px-3 py-2 rounded-md', filter === id ? 'bg-accent font-medium' : 'text-muted-foreground hover:bg-accent/50')}
            >
              <span>{label}</span>
              {count > 0 && <Badge variant="secondary" className="h-5 px-1.5 text-xs">{count}</Badge>}
            </button>
          ))}
        </nav>
      </aside>

      {/* Item list */}
      <div className="w-80 border-r flex flex-col shrink-0">
        <div className="px-4 py-3 border-b flex items-center justify-between">
          <span className="text-sm font-medium">{filter.charAt(0).toUpperCase() + filter.slice(1)}</span>
          <Button variant="ghost" size="sm">Mark all read</Button>
        </div>
        <ScrollArea className="flex-1">
          <div className="flex flex-col">
            {/* Item rows */}
          </div>
        </ScrollArea>
      </div>

      {/* Action panel */}
      <main className="flex-1 flex flex-col">
        {selected ? (
          <ScrollArea className="flex-1">
            <div className="p-6 flex flex-col gap-4">
              {/* Item detail and triage actions */}
            </div>
          </ScrollArea>
        ) : (
          <div className="flex-1 flex items-center justify-center">
            <p className="text-sm text-muted-foreground">Select an item</p>
          </div>
        )}
      </main>

    </div>
  )
}

